from flask import Flask, request, redirect, url_for, session
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'

@app.route('/login')
def login():
    auth_url = f'https://example.com/oauth/authorize?response_type=code&client_id=your_client_id_here&redirect_uri=https://yourdomain.com/callback'
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return 'Error: No authorization code provided', 400

    token_url = f'https://example.com/oauth/token'
    headers = {'Content-Type': 'application/x-www-form-urlencoded'}
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': 'https://yourdomain.com/callback',
        'client_id': 'your_client_id_here',
        'client_secret': 'your_client_secret_here'
    }

    response = requests.post(token_url, headers=headers, data=data)
    if response.status_code == 200:
        token_data = response.json()
        session['access_token'] = token_data.get('access_token')
        return redirect(url_for('protected_route'))
    else:
        return 'Error: Failed to obtain access token', 400

if __name__ == '__main__':
    app.run(debug=True)